+  --success-bg:    #f0fdf4;
+  --success-border:#86efac;
+  --warning:       #92400e;
+  --warning-bg:    #fffbeb;
+  --orange:        #ea580c;
+  --orange-bg:     #fff7ed;
+  --purple:        #6d28d9;
+  --purple-bg:     #f5f3ff;
