// в”Ђв”Ђ Profile Form в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
function initProfile() {
  // Load saved profile on start
  fetch("/api/profile")
    .then(r => r.json())
    .then(profile => {
      state.profile = profile;
      if (profile.name)       $("pName").value       = profile.name;
      if (profile.location)   $("pLocation").value   = profile.location;
      if (profile.occupation) $("pOccupation").value = profile.occupation;
