+// в”Ђв”Ђ Chat: Send Message в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
+async function sendMessage(message) {
+  const text = (message || chatInput.value).trim();
+  if (!text || state.isSending) return;
+
+  state.isSending = true;
+  sendBtn.disabled = true;
+  chatInput.value = "";
+  autoResizeTextarea(chatInput);
+
+  // Add user message
+  appendMessage("user", text, state.currentMode);
+
+  // Show typing
+  showTyping(true);
+  setStatus("thinking", "Thinking...");
+
