+  initVoiceInput();
+  chatInput.focus();
+
+  // Health check on load
+  fetch("/api/health")
+    .then(r => r.json())
+    .then(data => {
+      if (!data.watsonx_configured) {
+        appendMessage("assistant",
+          "вљ пёЏ **Configuration needed**: WATSONX_API_KEY and WATSONX_PROJECT_ID are not set. " +
