  stats.forEach(el => {
    if (el && el.textContent === "вЂ”") {
      el.textContent = "0";
    }
  });

  // Chat count from session
  fetch("/api/profile")
    .then(r => r.json())
    .then(() => {
      // Stats update when user actually runs queries
    })
    .catch(() => {});
}

