+    srAnnouncer.style.cssText = "position:absolute;left:-9999px;width:1px;height:1px;overflow:hidden";
+    document.body.appendChild(srAnnouncer);
+  }
+  srAnnouncer.textContent = "";
+  setTimeout(() => { srAnnouncer.textContent = message; }, 50);
+}
+
+// в”Ђв”Ђ Load Profile в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
+function loadProfile() {
+  fetch("/api/profile")
+    .then(r => r.json())
