+  };
+
+  recognition.onend = () => {
+    isListening = false;
+    dashMicBtn.classList.remove("listening");
+    dashMicBtn.setAttribute("aria-pressed", "false");
+    dashMicIcon.className = "bi bi-mic-fill";
+    dashMicLabel.textContent = "Tap to Speak";
+    dashVoiceStatus.hidden = true;
